func (mmUpdateKeyVersion *mRepositoryMockUpdateKeyVersion) When(kv *models.KeyVersion) *RepositoryMockUpdateKeyVersionExpectation {
	if mmUpdateKeyVersion.mock.funcUpdateKeyVersion != nil {
		mmUpdateKeyVersion.mock.t.Fatalf("RepositoryMock.UpdateKeyVersion mock is already set by Set")
	}

	expectation := &RepositoryMockUpdateKeyVersionExpectation{
		mock:               mmUpdateKeyVersion.mock,
		params:             &RepositoryMockUpdateKeyVersionParams{kv},
		expectationOrigins: RepositoryMockUpdateKeyVersionExpectationOrigins{origin: minimock.CallerInfo(1)},
	}
	mmUpdateKeyVersion.expectations = append(mmUpdateKeyVersion.expectations, expectation)
	return expectation
}

// Then sets up Repository.UpdateKeyVersion return parameters for the expectation previously defined by the When method
func (e *RepositoryMockUpdateKeyVersionExpectation) Then(err error) *RepositoryMock {
	e.results = &RepositoryMockUpdateKeyVersionResults{err}
	return e.mock
}

// Times sets number of times Repository.UpdateKeyVersion should be invoked
func (mmUpdateKeyVersion *mRepositoryMockUpdateKeyVersion) Times(n uint64) *mRepositoryMockUpdateKeyVersion {
	if n == 0 {
		mmUpdateKeyVersion.mock.t.Fatalf("Times of RepositoryMock.UpdateKeyVersion mock can not be zero")
	}
	mm_atomic.StoreUint64(&mmUpdateKeyVersion.expectedInvocations, n)
	mmUpdateKeyVersion.expectedInvocationsOrigin = minimock.CallerInfo(1)
	return mmUpdateKeyVersion
}

func (mmUpdateKeyVersion *mRepositoryMockUpdateKeyVersion) invocationsDone() bool {
	if len(mmUpdateKeyVersion.expectations) == 0 && mmUpdateKeyVersion.defaultExpectation == nil && mmUpdateKeyVersion.mock.funcUpdateKeyVersion == nil {
		return true
	}

	totalInvocations := mm_atomic.LoadUint64(&mmUpdateKeyVersion.mock.afterUpdateKeyVersionCounter)
	expectedInvocations := mm_atomic.LoadUint64(&mmUpdateKeyVersion.expectedInvocations)

	return totalInvocations > 0 && (expectedInvocations == 0 || expectedInvocations == totalInvocations)
}

// UpdateKeyVersion implements mm_keys.Repository
func (mmUpdateKeyVersion *RepositoryMock) UpdateKeyVersion(kv *models.KeyVersion) (err error) {
	mm_atomic.AddUint64(&mmUpdateKeyVersion.beforeUpdateKeyVersionCounter, 1)
	defer mm_atomic.AddUint64(&mmUpdateKeyVersion.afterUpdateKeyVersionCounter, 1)

	mmUpdateKeyVersion.t.Helper()

	if mmUpdateKeyVersion.inspectFuncUpdateKeyVersion != nil {
		mmUpdateKeyVersion.inspectFuncUpdateKeyVersion(kv)
	}

	mm_params := RepositoryMockUpdateKeyVersionParams{kv}

	// Record call args
	mmUpdateKeyVersion.UpdateKeyVersionMock.mutex.Lock()
	mmUpdateKeyVersion.UpdateKeyVersionMock.callArgs = append(mmUpdateKeyVersion.UpdateKeyVersionMock.callArgs, &mm_params)
	mmUpdateKeyVersion.UpdateKeyVersionMock.mutex.Unlock()

	for _, e := range mmUpdateKeyVersion.UpdateKeyVersionMock.expectations {
		if minimock.Equal(*e.params, mm_params) {
			mm_atomic.AddUint64(&e.Counter, 1)
			return e.results.err
		}
	}

	if mmUpdateKeyVersion.UpdateKeyVersionMock.defaultExpectation != nil {
		mm_atomic.AddUint64(&mmUpdateKeyVersion.UpdateKeyVersionMock.defaultExpectation.Counter, 1)
		mm_want := mmUpdateKeyVersion.UpdateKeyVersionMock.defaultExpectation.params
		mm_want_ptrs := mmUpdateKeyVersion.UpdateKeyVersionMock.defaultExpectation.paramPtrs

		mm_got := RepositoryMockUpdateKeyVersionParams{kv}

		if mm_want_ptrs != nil {

			if mm_want_ptrs.kv != nil && !minimock.Equal(*mm_want_ptrs.kv, mm_got.kv) {
				mmUpdateKeyVersion.t.Errorf("RepositoryMock.UpdateKeyVersion got unexpected parameter kv, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmUpdateKeyVersion.UpdateKeyVersionMock.defaultExpectation.expectationOrigins.originKv, *mm_want_ptrs.kv, mm_got.kv, minimock.Diff(*mm_want_ptrs.kv, mm_got.kv))
			}

		} else if mm_want != nil && !minimock.Equal(*mm_want, mm_got) {
			mmUpdateKeyVersion.t.Errorf("RepositoryMock.UpdateKeyVersion got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmUpdateKeyVersion.UpdateKeyVersionMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
		}

		mm_results := mmUpdateKeyVersion.UpdateKeyVersionMock.defaultExpectation.results
		if mm_results == nil {
			mmUpdateKeyVersion.t.Fatal("No results are set for the RepositoryMock.UpdateKeyVersion")
		}
		return (*mm_results).err
	}
	if mmUpdateKeyVersion.funcUpdateKeyVersion != nil {
		return mmUpdateKeyVersion.funcUpdateKeyVersion(kv)
	}
	mmUpdateKeyVersion.t.Fatalf("Unexpected call to RepositoryMock.UpdateKeyVersion. %v", kv)
	return
}

// UpdateKeyVersionAfterCounter returns a count of finished RepositoryMock.UpdateKeyVersion invocations
func (mmUpdateKeyVersion *RepositoryMock) UpdateKeyVersionAfterCounter() uint64 {
	return mm_atomic.LoadUint64(&mmUpdateKeyVersion.afterUpdateKeyVersionCounter)
}

// UpdateKeyVersionBeforeCounter returns a count of RepositoryMock.UpdateKeyVersion invocations
func (mmUpdateKeyVersion *RepositoryMock) UpdateKeyVersionBeforeCounter() uint64 {
	return mm_atomic.LoadUint64(&mmUpdateKeyVersion.beforeUpdateKeyVersionCounter)
}

// Calls returns a list of arguments used in each call to RepositoryMock.UpdateKeyVersion.
// The list is in the same order as the calls were made (i.e. recent calls have a higher index)
func (mmUpdateKeyVersion *mRepositoryMockUpdateKeyVersion) Calls() []*RepositoryMockUpdateKeyVersionParams {
	mmUpdateKeyVersion.mutex.RLock()

	argCopy := make([]*RepositoryMockUpdateKeyVersionParams, len(mmUpdateKeyVersion.callArgs))
	copy(argCopy, mmUpdateKeyVersion.callArgs)

	mmUpdateKeyVersion.mutex.RUnlock()

	return argCopy
}

// MinimockUpdateKeyVersionDone returns true if the count of the UpdateKeyVersion invocations corresponds
// the number of defined expectations
func (m *RepositoryMock) MinimockUpdateKeyVersionDone() bool {
	if m.UpdateKeyVersionMock.optional {
		// Optional methods provide '0 or more' call count restriction.
		return true
	}

	for _, e := range m.UpdateKeyVersionMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			return false
		}
	}

	return m.UpdateKeyVersionMock.invocationsDone()
}

// MinimockUpdateKeyVersionInspect logs each unmet expectation
func (m *RepositoryMock) MinimockUpdateKeyVersionInspect() {
	for _, e := range m.UpdateKeyVersionMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to RepositoryMock.UpdateKeyVersion at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterUpdateKeyVersionCounter := mm_atomic.LoadUint64(&m.afterUpdateKeyVersionCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.UpdateKeyVersionMock.defaultExpectation != nil && afterUpdateKeyVersionCounter < 1 {
		if m.UpdateKeyVersionMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to RepositoryMock.UpdateKeyVersion at\n%s", m.UpdateKeyVersionMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to RepositoryMock.UpdateKeyVersion at\n%s with params: %#v", m.UpdateKeyVersionMock.defaultExpectation.expectationOrigins.origin, *m.UpdateKeyVersionMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcUpdateKeyVersion != nil && afterUpdateKeyVersionCounter < 1 {
		m.t.Errorf("Expected call to RepositoryMock.UpdateKeyVersion at\n%s", m.funcUpdateKeyVersionOrigin)
	}

	if !m.UpdateKeyVersionMock.invocationsDone() && afterUpdateKeyVersionCounter > 0 {
		m.t.Errorf("Expected %d calls to RepositoryMock.UpdateKeyVersion at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.UpdateKeyVersionMock.expectedInvocations), m.UpdateKeyVersionMock.expectedInvocationsOrigin, afterUpdateKeyVersionCounter)
	}
}

// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *RepositoryMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockCreateKeyVersionInspect()

			m.MinimockGetActiveKeyVersionInspect()

			m.MinimockGetKeyVersionInspect()

			m.MinimockListKeyVersionsInspect()

			m.MinimockUpdateKeyVersionInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *RepositoryMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *RepositoryMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockCreateKeyVersionDone() &&
		m.MinimockGetActiveKeyVersionDone() &&
		m.MinimockGetKeyVersionDone() &&
		m.MinimockListKeyVersionsDone() &&
		m.MinimockUpdateKeyVersionDone()
}
